// src/services/quizCustomerService.js
import axios from 'axios';

const API_URL = 'http://localhost:3001'; // Your Rails API URL

// Fetch all quiz customers
export const fetchQuizCustomers = async () => {
  try {
    const response = await axios.get(`${API_URL}/quiz_customers`);
    return response.data;
  } catch (error) {
    console.error("Error fetching quiz customers:", error);
    throw error;
  }
};

// Fetch a single quiz customer by ID
export const fetchQuizCustomerById = async (id) => {
  try {
    const response = await axios.get(`${API_URL}/quiz_customers/${id}`);
    return response.data;
  } catch (error) {
    console.error(`Error fetching quiz customer with ID ${id}:`, error);
    throw error;
  }
};

// Create a new quiz customer
export const createQuizCustomer = async (customerData) => {
  try {
    const response = await axios.post(`${API_URL}/quiz_customers`, customerData);
    return response.data;
  } catch (error) {
    console.error("Error creating quiz customer:", error);
    throw error;
  }
};
